from llama_stack_client import LlamaStackAgent

class AdaptiveAgent:
    def __init__(self):
        self.agent = LlamaStackAgent()

    def run_adaptive(self, task: str, max_turns: int = 15) -> dict:
        result = self.agent.run(task, max_turns=max_turns)
        if result.get('progress_score', 0) < 0.3 and result['turns_used'] < max_turns * 0.7:
            # Extend turns for complex tasks
            return self.agent.run(task, max_turns=max_turns + 5, resume=True)
        return result

agent = AdaptiveAgent()
result = agent.run_adaptive('complex analysis task')
